import React, { useState, useRef, useEffect } from 'react';
import { Box } from '@mui/material';
import { shapeDefinitions, defaultShape } from './shapes';
import Canvas from './components/Canvas';
import Sidebar from './components/Sidebar';
import CodePreview from './components/CodePreview';
import Toolbar from './components/Toolbar';
import BottomBar from './components/BottomBar';
import './styles/App.css';

const App = () => {
  const [figures, setFigures] = useState([]);
  const [selectedShape, setSelectedShape] = useState(defaultShape);
  const [shapeParams, setShapeParams] = useState({});
  const [color, setColor] = useState('#000000');
  const [lineWidth, setLineWidth] = useState(5);
  const [isDrawing, setIsDrawing] = useState(false);
  const [undoStack, setUndoStack] = useState([]);
  const [redoStack, setRedoStack] = useState([]);
  const canvasRef = useRef(null);
  const contextRef = useRef(null);
  const containerRef = useRef(null);
  const [mousePos, setMousePos] = useState({ x: 0, y: 0 });

  const initializeCanvas = () => {
    const canvas = canvasRef.current;
    const container = containerRef.current;
    
    // Set canvas size to match container size
    canvas.width = container.offsetWidth;
    canvas.height = container.offsetHeight;

    const context = canvas.getContext('2d');
    context.lineCap = 'round';
    context.lineJoin = 'round';
    context.strokeStyle = color;
    context.lineWidth = lineWidth;
    contextRef.current = context;

    // Save initial blank state
    saveToUndoStack();
  };

  useEffect(() => {
    initializeCanvas();

    // Handle window resize
    const handleResize = () => {
      initializeCanvas();
    };

    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  const saveToUndoStack = () => {
    if (canvasRef.current) {
      const imageData = canvasRef.current.toDataURL();
      setUndoStack(prev => [...prev, imageData]);
      setRedoStack([]);
    }
  };

  const startDrawing = ({ nativeEvent }) => {
    const { offsetX, offsetY } = nativeEvent;
    contextRef.current.beginPath();
    contextRef.current.moveTo(offsetX, offsetY);
    setIsDrawing(true);
  };

  const draw = ({ nativeEvent }) => {
    if (!isDrawing) return;
    const { offsetX, offsetY } = nativeEvent;
    contextRef.current.lineTo(offsetX, offsetY);
    contextRef.current.stroke();
  };

  const finishDrawing = () => {
    if (isDrawing) {
      contextRef.current.closePath();
      setIsDrawing(false);
      saveToUndoStack();
    }
  };

  const clearCanvas = () => {
    if (canvasRef.current) {
      const context = contextRef.current;
      context.clearRect(0, 0, canvasRef.current.width, canvasRef.current.height);
      saveToUndoStack();
    }
  };

  const undo = () => {
    if (undoStack.length > 1) {
      const newUndoStack = [...undoStack];
      const currentState = newUndoStack.pop();
      setRedoStack(prev => [...prev, currentState]);
      setUndoStack(newUndoStack);
      
      const img = new Image();
      img.src = newUndoStack[newUndoStack.length - 1];
      img.onload = () => {
        contextRef.current.clearRect(0, 0, canvasRef.current.width, canvasRef.current.height);
        contextRef.current.drawImage(img, 0, 0);
      };
    }
  };

  const redo = () => {
    if (redoStack.length > 0) {
      const newRedoStack = [...redoStack];
      const nextState = newRedoStack.pop();
      setRedoStack(newRedoStack);
      setUndoStack(prev => [...prev, nextState]);
      
      const img = new Image();
      img.src = nextState;
      img.onload = () => {
        contextRef.current.clearRect(0, 0, canvasRef.current.width, canvasRef.current.height);
        contextRef.current.drawImage(img, 0, 0);
      };
    }
  };

  const saveCanvas = () => {
    if (canvasRef.current) {
      const link = document.createElement('a');
      link.download = 'drawing.png';
      link.href = canvasRef.current.toDataURL();
      link.click();
    }
  };

  useEffect(() => {
    if (contextRef.current) {
      contextRef.current.strokeStyle = color;
    }
  }, [color]);

  useEffect(() => {
    if (contextRef.current) {
      contextRef.current.lineWidth = lineWidth;
    }
  }, [lineWidth]);

  const handleMouseMove = (e) => {
    const canvas = e.target;
    const rect = canvas.getBoundingClientRect();
    const x = e.clientX - rect.left - canvas.width / 2;
    const y = canvas.height / 2 - (e.clientY - rect.top);
    setMousePos({ x, y });
  };

  const handleShapeSelect = (shape) => {
    setSelectedShape(shape);
    setShapeParams({});
  };

  const handleParamChange = (param, value) => {
    setShapeParams(prev => ({
      ...prev,
      [param]: Number(value)
    }));
  };

  const handleDraw = () => {
    if (selectedShape === defaultShape) return;

    const newFigure = {
      type: selectedShape,
      params: shapeParams,
      color,
      lineWidth
    };

    const newFigures = [...figures, newFigure];
    setFigures(newFigures);
    setUndoStack([...undoStack, newFigures.map(f => f.type).join(',')]);
    setRedoStack([]);
  };

  const handleDelete = () => {
    const newFigures = figures.filter((_, index) => index !== figures.length - 1);
    setFigures(newFigures);
    setUndoStack([...undoStack, newFigures.map(f => f.type).join(',')]);
    setRedoStack([]);
  };

  return (
    <Box className="app-container">
      <Toolbar
        onUndo={undo}
        onRedo={redo}
        onDelete={handleDelete}
      />

      <div className="app-body">
        <Sidebar
          selectedShape={selectedShape}
          onShapeSelect={handleShapeSelect}
          shapeParams={shapeParams}
          onParamChange={handleParamChange}
          color={color}
          onColorChange={setColor}
          lineWidth={lineWidth}
          onLineWidthChange={setLineWidth}
          mousePos={mousePos}
        />

        <div className="main-content-area">
          <div className="canvas-code-container">
            <div className="canvas-column">
              <Box className="canvas-container">
                <Box className="canvas-header">
                  Drawing Canvas
                </Box>
                <Box className="canvas-area" ref={containerRef}>
                  <canvas
                    ref={canvasRef}
                    onMouseDown={startDrawing}
                    onMouseMove={draw}
                    onMouseUp={finishDrawing}
                    onMouseLeave={finishDrawing}
                  />
                </Box>
              </Box>
            </div>
            <CodePreview figures={figures} />
          </div>
        </div>
      </div>

      <BottomBar
        onDraw={handleDraw}
        onUndo={undo}
        onRedo={redo}
        onClear={clearCanvas}
      />
    </Box>
  );
};

export default App;
